1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const parseCellKey = (k: string): Cell => {
12	  const [x, y] = k.split(",").map(Number);
13	  return [x, y];
14	};
15	
16	export const nextGeneration = (cells: Cell[]): Cell[] => {
17	  const liveSet = new Set(cells.map(cellKey));
18	
19	  const neighborCounts = new Map<string, number>();
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const k = cellKey([x + dx, y + dy]);
23	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
24	    }
25	  }
26	
27	  const survives = (k: string, count: number): boolean =>
28	    count === 3 || (count === 2 && liveSet.has(k));
29	
30	  const nextCells: Cell[] = [];
31	  for (const [k, count] of neighborCounts) {
32	    if (survives(k, count)) nextCells.push(parseCellKey(k));
33	  }
34	  return nextCells;
35	};
